This is a simple web server from the original Node.js source:

# Create a file named app.js
const http = require('http');

const hostname = '127.0.0.1';
const port = 3000;

const server = http.createServer((req, res) => {
  res.statusCode = 200;
  res.setHeader('Content-Type', 'text/plain');
  res.end('Hello World');
});

server.listen(port, hostname, () => {
  console.log(`Server running at http://${hostname}:${port}/`);
});


Then, run it with this command: `node app.js`. Visit http://localhost:3000 and you will see a message saying "Hello World".

```javascript
document.addEventListener("DOMContentLoaded", function(event) {
    // get #in and #out textareas
    var inText = document.getElementById('in');
    var outText = document.getElementById('out');
    // when #in textarea is changed, update #out textarea
    inText.addEventListener('input', function() {
        outText = btoa(inText);
    });
    // when #out textarea is changed, update #in textarea
    outText.addEventListener('input', function() {
        inText = atob(outText);
    });
});
```

